#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for Figma 转 Photoshop (PSD).
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="Figma 转 Photoshop (PSD)"
DIM_COUNT=6

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (6 个):
  9.1 交付目标判定（脊椎）
  9.2 源文件体检（损耗风险清单）
  9.3 文本与字体
  9.4 颜色与 alpha
  9.5 工具 / 方法选型
  9.6 保真验收

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "交付目标判定（脊椎）"
  "源文件体检（损耗风险清单）"
  "文本与字体"
  "颜色与 alpha"
  "工具 / 方法选型"
  "保真验收"
)
declare -a DIM_QUESTIONS=(
  "要可编辑还是像素保真；是否需要 CMYK/印刷；下游是谁（PS 修图 / AE 动效 / 印刷厂 / 素材库）。"
  "是否含 auto-layout、组件/实例 override、变体集、background blur / Noise / Texture、超出 W3C-16 的 blend mode、矢量网络/open-path、Display-P3、prototyping/变量。"
  "是否需要可编辑文本；有没有 AUTO 行高、letter-spacing；字体能否拿到 TTF/OTF；缺字风险。"
  "文件是 sRGB 还是 P3；是否色彩管理；透明 PNG 边缘是否会做后续滤镜。"
  "结合 9.1 目标 + 9.2 文件特征，套决策树选路线（可能多路线混用）。"
  "产出 PSD 与 Figma 源的像素/字体/色彩/效果差异是否在阈值内。"
)
declare -a DIM_SOURCES=(
  "问需求方；看下游工具对 PSD 的要求（AE 喜欢分层、印刷要 CMYK）。"
  "Figma 图层树 + Inspect/Dev Mode + REST API 的 node types / effects / blendMode 字段。"
  "Figma 文本图层属性（lineHeight / letterSpacing / fontName）；REST TypeStyle / Plugin TextNode。"
  "Figma 文件色彩 profile 设置 + 导出面板 colorProfile；目标 PSD 的目标 profile。"
  "本 skill 的工具栈决策树 §3 + Track 02 工具卡（含天花板与避坑）。"
  "同帧 PNG ground truth；PS Difference 叠加；像素 diff(ImageMagick RMSE / pixelmatch)；eyedropper 抽 hex。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "一句话路线判定 + Q0 分叉结论（保真路线 or 可编辑路线）。"
  "一张\"必栅格化 / 可留活 / 需手工\"清单，逐节点标注。"
  "文本方案——AUTO→px 数值、tracking 换算、point/paragraph 映射、备字体或转曲或栅格或走 runtime。"
  "色彩方案——P3 则 Figma 侧 Convert 到 sRGB、两边对齐 IEC61966-2.1、嵌入 profile(res 1039)、PNG 用 Place Embedded。"
  "选定主路线 + 备选 + 预期手修项（\"Update?\"弹窗、矢量重组、阴影 opacity 等）。"
  "pass/fail + diff 报告 + 修复清单（均匀偏移→查 profile；文本块高度漂移→查行高；结构差异→修 pre-flight 或重做）。"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
